import React, { useState } from 'react';
import toast from 'react-hot-toast';

const MOCK = [
  { id:1, no:'REG001', name:'Riya Gupta',   parent:'Sanjay Gupta',  phone:'9811001100', class_:'Class 6', fee:500, paid:true,  date:'2025-06-05', status:'pending'   },
  { id:2, no:'REG002', name:'Rahul Sharma', parent:'Amit Sharma',   phone:'9822002200', class_:'Class 9', fee:500, paid:false, date:'2025-06-04', status:'pending'   },
  { id:3, no:'REG003', name:'Pooja Verma',  parent:'Dinesh Verma',  phone:'9833003300', class_:'Class 7', fee:500, paid:true,  date:'2025-06-03', status:'converted' },
];

const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];
const inp = { width:'100%', padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:8, fontSize:13, outline:'none', fontFamily:'inherit' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

export default function Registration() {
  const [registrations, setRegistrations] = useState(MOCK);
  const [showAdd, setShowAdd] = useState(false);
  const [showAddClass, setShowAddClass] = useState(false);
  const [classes, setClasses] = useState(CLASSES);
  const [newClass, setNewClass] = useState('');
  const [form, setForm] = useState({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false });

  const handleAdd = (e) => {
    e.preventDefault();
    const reg = {
      ...form, id: registrations.length+1,
      no: `REG${String(registrations.length+4).padStart(3,'0')}`,
      fee: parseInt(form.regFee) || 500,
      paid: form.feePaid,
      date: new Date().toISOString().split('T')[0],
      status: 'pending'
    };
    setRegistrations([reg, ...registrations]);
    toast.success(`Registration ${reg.no} created for ${reg.name}`);
    setShowAdd(false);
    setForm({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false });
  };

  const handleAddClass = () => {
    if (!newClass.trim()) return;
    if (classes.includes(newClass.trim())) { toast.error('Class already exists!'); return; }
    setClasses([...classes, newClass.trim()]);
    toast.success(`Class "${newClass.trim()}" added!`);
    setNewClass('');
    setShowAddClass(false);
  };

  const convert = (id) => {
    setRegistrations(registrations.map(r => r.id===id ? {...r, status:'converted'} : r));
    toast.success('Converted to Admission! Student can now be admitted.');
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Registration Management</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Register students before formal admission</p></div>
        <div style={{display:'flex',gap:10}}>
          <button onClick={()=>setShowAddClass(true)} style={{padding:'8px 14px',border:'1.5px solid #1E1B4B',borderRadius:8,background:'#EDE9F8',color:'#1E1B4B',fontSize:12,fontWeight:600,cursor:'pointer'}}>+ Add Class</button>
          <button onClick={()=>setShowAdd(true)} style={{padding:'8px 18px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Registration</button>
        </div>
      </div>

      <div style={{display:'flex',gap:12,marginBottom:16}}>
        {[['Total',registrations.length,'#EDE9F8','#1E1B4B'],['Pending',registrations.filter(r=>r.status==='pending').length,'#FEF3C7','#92400E'],['Converted',registrations.filter(r=>r.status==='converted').length,'#D1FAE5','#065F46'],['Fee Paid',registrations.filter(r=>r.paid).length,'#DBEAFE','#1E40AF']].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'12px 18px',background:bg,borderRadius:10,flex:1,textAlign:'center'}}>
            <div style={{fontSize:22,fontWeight:700,color:c}}>{v}</div>
            <div style={{fontSize:11,color:c,opacity:.8}}>{l}</div>
          </div>
        ))}
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Reg No','Student','Parent / Phone','Class','Reg Fee','Date','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {registrations.map(r=>(
              <tr key={r.id} style={{borderBottom:'0.5px solid #F3F4F6'}}>
                <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{r.no}</td>
                <td style={{padding:'10px 12px',fontWeight:600}}>{r.name}</td>
                <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{r.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{r.phone}</div></td>
                <td style={{padding:'10px 12px',color:'#6B7280'}}>{r.class_}</td>
                <td style={{padding:'10px 12px'}}>
                  <div style={{fontWeight:600}}>₹{r.fee}</div>
                  <span style={{padding:'1px 6px',borderRadius:10,fontSize:9,background:r.paid?'#D1FAE5':'#FEE2E2',color:r.paid?'#065F46':'#991B1B'}}>{r.paid?'Paid':'Unpaid'}</span>
                </td>
                <td style={{padding:'10px 12px',color:'#6B7280'}}>{r.date}</td>
                <td style={{padding:'10px 12px'}}>
                  <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:r.status==='converted'?'#D1FAE5':'#FEF3C7',color:r.status==='converted'?'#065F46':'#92400E'}}>
                    {r.status==='converted'?'✅ Converted':'⏳ Pending'}
                  </span>
                </td>
                <td style={{padding:'10px 12px'}}>
                  {r.status==='pending' ? (
                    <button onClick={()=>convert(r.id)} style={{padding:'4px 10px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:6,fontSize:11,cursor:'pointer'}}>→ Convert</button>
                  ) : (
                    <span style={{fontSize:11,color:'#9CA3AF'}}>Admitted</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Add Class Modal */}
      {showAddClass && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.45)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:400,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>+ Add New Class</div>
              <button onClick={()=>setShowAddClass(false)} style={{background:'#F3F4F6',border:'none',borderRadius:7,width:30,height:30,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <label style={lbl}>Class Name <span style={{color:'#DC2626'}}>*</span></label>
              <input value={newClass} onChange={e=>setNewClass(e.target.value)} placeholder="e.g. Class 6, LKG, Nursery" style={{...inp,marginBottom:16}}/>
              <div style={{marginBottom:16}}>
                <div style={{fontSize:11,fontWeight:700,color:'#6B7280',marginBottom:8}}>Existing Classes:</div>
                <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
                  {classes.map(c=><span key={c} style={{padding:'3px 10px',background:'#EDE9F8',borderRadius:20,fontSize:11,color:'#1E1B4B'}}>{c}</span>)}
                </div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button onClick={()=>setShowAddClass(false)} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={handleAddClass} style={{padding:'9px 22px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>Add Class</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add Registration Modal */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.45)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:560,maxWidth:'100%',overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>📄 New Registration</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:7,width:30,height:30,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>Parent Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile <span style={{color:'#DC2626'}}>*</span></label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div>
                  <label style={lbl}>Class <span style={{color:'#DC2626'}}>*</span></label>
                  <div style={{display:'flex',gap:6}}>
                    <select required value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={{...inp,flex:1}}>
                      <option value="">Select class</option>
                      {classes.map(c=><option key={c}>{c}</option>)}
                    </select>
                    <button type="button" onClick={()=>setShowAddClass(true)} title="Add new class" style={{padding:'0 10px',border:'1.5px solid #1E1B4B',borderRadius:8,background:'#EDE9F8',color:'#1E1B4B',fontWeight:700,cursor:'pointer',fontSize:16}}>+</button>
                  </div>
                  <div style={{fontSize:10,color:'#9CA3AF',marginTop:4}}>Class not listed? Click + to add it</div>
                </div>
                <div><label style={lbl}>Previous School</label><input value={form.prevSchool} onChange={e=>setForm({...form,prevSchool:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Registration Fee (₹)</label><input type="number" value={form.regFee} onChange={e=>setForm({...form,regFee:e.target.value})} style={inp}/></div>
                <div style={{display:'flex',alignItems:'center',gap:10,paddingTop:22}}>
                  <input type="checkbox" id="feePaid" checked={form.feePaid} onChange={e=>setForm({...form,feePaid:e.target.checked})} style={{width:16,height:16,accentColor:'#1E1B4B',cursor:'pointer'}}/>
                  <label htmlFor="feePaid" style={{fontSize:13,fontWeight:500,cursor:'pointer'}}>Fee Paid</label>
                </div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'9px 22px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>💾 Save Registration</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
